import React, { useEffect, useMemo, useState } from 'react';
import { motion } from 'framer-motion';
import { useAppContext } from '../context/AppContext';
import UploadDropzone from '../components/UploadDropzone';
import BreedInfoGrid from '../components/BreedInfoGrid';
import { predictImage, fetchBreedInfo } from '../api';

export default function Classifier() {
  const { activePrediction, addPrediction } = useAppContext();
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState('');
  const [fileName, setFileName] = useState('');
  const [predictions, setPredictions] = useState([]);
  const [breedInfo, setBreedInfo] = useState(null);
  const [topBreed, setTopBreed] = useState('');
  const [animalType, setAnimalType] = useState('');
  const [error, setError] = useState('');
  const [breedError, setBreedError] = useState('');
  const [loading, setLoading] = useState(false);
  const [breedLoading, setBreedLoading] = useState(false);

  useEffect(() => {
    if (!activePrediction) {
      return;
    }
    setPreview(activePrediction.previewDataUrl || '');
    setFileName(activePrediction.fileName || 'Saved preview');
    setPredictions(activePrediction.predictions || []);
    setBreedInfo(activePrediction.breedInfo || null);
    setTopBreed(activePrediction.breedName || '');
    setAnimalType(activePrediction.animalType || '');
  }, [activePrediction]);

  const handleFileSelect = (nextFile, dataUrl) => {
    setFile(nextFile);
    setPreview(dataUrl);
    setFileName(nextFile.name);
    setPredictions([]);
    setBreedInfo(null);
    setTopBreed('');
    setError('');
    setBreedError('');
  };

  const handleRemove = () => {
    setFile(null);
    setPreview('');
    setFileName('');
    setPredictions([]);
    setBreedInfo(null);
    setTopBreed('');
    setError('');
    setBreedError('');
  };

  const loadBreedInfo = async (breedName) => {
    setBreedLoading(true);
    setBreedError('');

    try {
      const { info, warning } = await fetchBreedInfo(breedName);
      setBreedInfo(info);
      if (warning) {
        setBreedError(warning);
      }
      return info;
    } catch (err) {
      setBreedError(err.message);
      return null;
    } finally {
      setBreedLoading(false);
    }
  };

  const handleClassify = async () => {
    if (!file) {
      setError('Please select an image to classify.');
      return;
    }

    setLoading(true);
    setError('');
    setPredictions([]);
    setBreedInfo(null);
    setTopBreed('');
    setBreedError('');

    try {
      const result = await predictImage(file);
      setPredictions(result.predictions || []);
      setTopBreed(result.top_breed || 'Unknown');
      setAnimalType(result.animal_type || 'Unknown');

      const info = await loadBreedInfo(result.top_breed);
      const savedItem = {
        breedName: result.top_breed,
        animalType: result.animal_type,
        predictions: result.predictions || [],
        previewDataUrl: preview,
        fileName,
        breedInfo: info,
      };
      addPrediction(savedItem);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const topPrediction = useMemo(() => predictions[0] || null, [predictions]);

  return (
    <div className="classifier-page">
      <div className="classifier-grid">
        <section className="classifier-panel">
          <div className="panel-header">
            <p className="panel-label">Classifier</p>
            <h2>Upload image</h2>
          </div>

          <UploadDropzone
            preview={preview}
            fileName={fileName}
            onFileSelect={handleFileSelect}
            onRemove={handleRemove}
            onSubmit={handleClassify}
            isLoading={loading}
            error={error}
          />
        </section>

        <motion.section
          className="results-panel"
          initial={{ opacity: 0, y: 16 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.32 }}
        >
          <div className="panel-header">
            <p className="panel-label">Prediction</p>
            <h2>Top results</h2>
          </div>

          {!topPrediction ? (
            <div className="empty-state">Upload an image to see the breed, confidence and summary cards.</div>
          ) : (
            <div className="prediction-summary">
              <div className="prediction-summary-title">{topPrediction.display_name}</div>
              <div className="prediction-summary-subtitle">{topPrediction.animal_type}</div>
              <div className="prediction-confidence">{topPrediction.confidence.toFixed(1)}%</div>
            </div>
          )}

          {predictions.length > 0 && (
            <div className="prediction-list">
              {predictions.map((prediction, index) => (
                <div key={prediction.label} className="prediction-item">
                  <div className="prediction-item-header">
                    <span>{index + 1}. {prediction.display_name}</span>
                    <span>{prediction.confidence.toFixed(1)}%</span>
                  </div>
                  <div className="progress-bar">
                    <motion.div
                      className="progress-fill"
                      initial={{ width: 0 }}
                      animate={{ width: `${Math.min(prediction.confidence, 100)}%` }}
                      transition={{ duration: 0.6, ease: 'easeOut' }}
                    />
                  </div>
                </div>
              ))}
            </div>
          )}
        </motion.section>
      </div>

      <BreedInfoGrid
        breedName={topBreed}
        info={breedInfo}
        loading={breedLoading}
        error={breedError}
      />
    </div>
  );
}
